import json

with open('baseline-packages.json') as f: baseline = json.load(f)
with open('after-cpm-packages.json') as f: after = json.load(f)

def extract(data):
    result = {}
    for p in data['projects']:
        name = p['path'].split('/')[-2]
        for fw in p['frameworks']:
            for pkg in fw.get('topLevelPackages', []):
                key = (name, pkg['id'])
                result[key] = pkg['resolvedVersion']
    return result

b = extract(baseline)
a = extract(after)

all_keys = sorted(set(b) | set(a))
changes = []
unchanged = []
for k in all_keys:
    bv = b.get(k, 'N/A')
    av = a.get(k, 'N/A')
    if bv != av:
        changes.append((k[0], k[1], bv, av))
    else:
        unchanged.append((k[0], k[1], bv))

print('=== CHANGES ===')
for proj, pkg, bv, av in changes:
    print(f'  {proj}/{pkg}: {bv} -> {av}')

print()
print('=== UNCHANGED ===')
for proj, pkg, v in unchanged:
    print(f'  {proj}/{pkg}: {v}')
